{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/dset/scopes/gov/schemas/artifact-types.schema.json",
  "title": "DSET artifact-type registry",
  "type": "object",
  "required": [
    "schema_version",
    "profile",
    "classification",
    "artifact_types",
    "path_rules"
  ],
  "properties": {
    "schema_version": {"const": 1.0},
    "profile": {"const": "documentation-v1"},
    "classification": {
      "type": "object",
      "required": ["unclassified", "multiple_matches", "direct_metadata_fields"],
      "properties": {
        "unclassified": {"const": "error"},
        "multiple_matches": {"const": "error"},
        "direct_metadata_fields": {
          "type": "object",
          "required": ["type", "subtype"],
          "properties": {
            "type": {"const": "artifact_type"},
            "subtype": {"const": "artifact_subtype"}
          },
          "additionalProperties": false
        }
      },
      "additionalProperties": false
    },
    "artifact_types": {
      "type": "array",
      "minItems": 1,
      "items": {"$ref": "#/$defs/artifact_type"}
    },
    "path_rules": {
      "type": "array",
      "items": {"$ref": "#/$defs/path_rule"}
    }
  },
  "$defs": {
    "id": {
      "type": "string",
      "pattern": "^[a-z][a-z0-9]*(?:_[a-z0-9]+)*$"
    },
    "artifact_type": {
      "type": "object",
      "required": ["id", "primary_question", "allow_empty_subtype", "subtypes"],
      "properties": {
        "id": {"$ref": "#/$defs/id"},
        "primary_question": {"type": "string", "minLength": 1},
        "allow_empty_subtype": {"type": "boolean"},
        "subtypes": {
          "type": "array",
          "items": {"$ref": "#/$defs/id"},
          "uniqueItems": true
        }
      },
      "additionalProperties": false
    },
    "path_rule": {
      "type": "object",
      "required": ["pattern", "artifact_type"],
      "properties": {
        "pattern": {"type": "string", "minLength": 1},
        "artifact_type": {"$ref": "#/$defs/id"},
        "artifact_subtype": {"$ref": "#/$defs/id"}
      },
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}

files.dset/scopes/gov/schemas/change.schema.js:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/dset/scopes/gov/schemas/change.schema.json",
  "title": "DSET change manifest",
  "type": "object",
  "required": ["schema_version", "id", "profile", "status", "packages", "pull_request", "requirements", "tests", "evals"],
  "properties": {
    "schema_version": {"oneOf": [{"enum": [1.0, 1.1]}, {"type": "string", "pattern": "^1\\.(?:0|1)-draft$"}, {"const": "1.2"}]},
    "id": {"type": "string", "minLength": 1},
    "slug": {"$ref": "#/$defs/kebab"},
    "profile": {"enum": ["small", "standard", "large", "defect", "adoption"]},
    "status": {"enum": ["proposed", "in-progress", "failed", "verified", "archive-ready", "archived"]},
    "primary_layer": {"$ref": "#/$defs/layer"},
    "affected_layers": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/layer"}},
    "workspace": {"$ref": "#/$defs/workspace"},
    "dependencies": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/dependency"}},
    "llm_session_ids": {"$ref": "#/$defs/llm_session_ids"},
    "rationale": {"$ref": "#/$defs/rationale"},
    "target": {"$ref": "#/$defs/target"},
    "packages": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"type": "string"}},
    "pull_request": {"$ref": "#/$defs/pr"},
    "release": {"oneOf": [{"$ref": "#/$defs/release"}, {"$ref": "#/$defs/layered_release"}]},
    "intake": {"$ref": "#/$defs/intake_ids"},
    "related_pull_requests": {"type": "array", "items": {"$ref": "#/$defs/related_pr"}},
    "requirements": {"$ref": "#/$defs/legacy_ids"},
    "tests": {"$ref": "#/$defs/legacy_ids"},
    "evals": {"$ref": "#/$defs/legacy_ids"},
    "adrs": {"$ref": "#/$defs/legacy_ids"},
    "decisions": {"$ref": "#/$defs/decision_ids"},
    "contracts": {"$ref": "#/$defs/contract_ids"},
    "stories": {"$ref": "#/$defs/story_ids"},
    "outcomes": {"$ref": "#/$defs/outcome_ids"},
    "archive": {"oneOf": [{"$ref": "#/$defs/legacy_archive"}, {"$ref": "#/$defs/layered_archive"}]}
  },
  "$defs": {
    "layer": {"enum": ["meta", "gov", "tool", "skill", "ops"]},
    "kebab": {"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"},
    "sha_or_pending": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{40}$"}, {"const": "pending"}]},
    "change_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-CHANGE-(?:META|GOV|TOOL|SKILL|OPS)-[0-9]{3,}$"},
    "trace_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-(?:REQUIREMENT|SCENARIO|INVARIANT|TEST|EVAL|TASK|PROBLEM|OPPORTUNITY|QUESTION|DECISION|CONTRACT|STORY|OUTCOME|CHANGE)(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"},
    "llm_session_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$"}},
    "rationale": {"type": "string", "minLength": 1, "maxLength": 4096},
    "legacy_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z0-9]+(?:-[A-Z0-9]+)+$"}},
    "requirement_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-REQUIREMENT(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "test_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-TEST(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "eval_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-EVAL(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "intake_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-(?:PROBLEM|OPPORTUNITY|QUESTION)(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "decision_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-DECISION(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "contract_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-CONTRACT(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "story_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-STORY(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "outcome_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-OUTCOME(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "pr": {
      "type": "object",
      "required": ["repository", "number", "url"],
      "properties": {
        "repository": {"type": "string", "pattern": "^[^/]+/[^/]+$"},
        "number": {"oneOf": [{"type": "integer", "minimum": 1}, {"const": "pending"}]},
        "url": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "exact_pr": {
      "type": "object",
      "required": ["repository", "number", "url"],
      "properties": {
        "repository": {"type": "string", "pattern": "^[^/]+/[^/]+$"},
        "number": {"type": "integer", "minimum": 1},
        "url": {"type": "string", "format": "uri", "pattern": "^https://"}
      },
      "additionalProperties": false
    },
    "workspace": {
      "type": "object",
      "required": ["isolation", "branch", "base_ref", "base_commit", "head_commit"],
      "properties": {
        "isolation": {"enum": ["integration-branch", "branch-worktree"]},
        "branch": {"type": "string", "minLength": 1},
        "base_ref": {"type": "string", "minLength": 1},
        "base_commit": {"$ref": "#/$defs/sha_or_pending"},
        "head_commit": {"$ref": "#/$defs/sha_or_pending"}
      },
      "additionalProperties": false
    },
    "dependency": {
      "type": "object",
      "required": ["change_id", "pull_request", "required_commit", "consumes", "claim", "use", "evidence", "checked_at", "reopen_when", "status"],
      "properties": {
        "change_id": {"$ref": "#/$defs/change_id"},
        "pull_request": {"$ref": "#/$defs/pr"},
        "required_commit": {"$ref": "#/$defs/sha_or_pending"},
        "consumes": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/trace_id"}},
        "claim": {"type": "string", "minLength": 1},
        "use": {"type": "string", "minLength": 1},
        "evidence": {"type": "string", "minLength": 1},
        "checked_at": {"type": "string", "format": "date"},
        "reopen_when": {"type": "string", "minLength": 1},
        "status": {"enum": ["planned", "available", "integrated", "blocked", "stale"]}
      },
      "allOf": [
        {
          "if": {"properties": {"status": {"enum": ["available", "integrated"]}}, "required": ["status"]},
          "then": {
            "properties": {
              "pull_request": {"$ref": "#/$defs/exact_pr"},
              "required_commit": {"type": "string", "pattern": "^[0-9a-f]{40}$"}
            }
          }
        }
      ],
      "additionalProperties": false
    },
    "target": {
      "type": "object",
      "required": ["repository", "work_areas"],
      "properties": {
        "repository": {"type": "boolean"},
        "work_areas": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/kebab"}}
      },
      "oneOf": [
        {
          "properties": {
            "repository": {"const": true},
            "work_areas": {"maxItems": 0}
          }
        },
        {
          "properties": {
            "repository": {"const": false},
            "work_areas": {"minItems": 1}
          }
        }
      ],
      "additionalProperties": false
    },
    "related_pr": {
      "type": "object",
      "required": ["number", "role"],
      "properties": {
        "number": {"type": "integer", "minimum": 1},
        "role": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "release": {
      "oneOf": [
        {"$ref": "#/$defs/release_declaration"},
        {"$ref": "#/$defs/release_reference"}
      ]
    },
    "release_declaration": {
      "type": "object",
      "required": ["policy", "class", "base", "target", "readiness", "candidate_commit"],
      "properties": {
        "policy": {"const": "dset/governance/release.md"},
        "class": {"enum": ["pending", "bootstrap", "small", "normal", "rc", "final", "breaking"]},
        "base": {
          "type": "object",
          "required": ["ref", "commit", "version"],
          "properties": {
            "ref": {"type": "string", "minLength": 1},
            "commit": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{40}$"}, {"const": "pending"}]},
            "version": {"oneOf": [{"const": "unversioned"}, {"const": "pending"}, {"$ref": "#/$defs/semver"}]}
          },
          "additionalProperties": false
        },
        "target": {"oneOf": [{"const": "pending"}, {"$ref": "#/$defs/semver"}]},
        "readiness": {"const": "verification.md"},
        "candidate_commit": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{40}$"}, {"const": "pending"}]}
      },
      "additionalProperties": false
    },
    "release_reference": {
      "type": "object",
      "required": ["owner_change"],
      "properties": {
        "owner_change": {"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"}
      },
      "additionalProperties": false
    },
    "layered_release": {
      "oneOf": [
        {"$ref": "#/$defs/layered_release_declaration"},
        {"$ref": "#/$defs/layered_release_reference"}
      ]
    },
    "layered_release_declaration": {
      "type": "object",
      "required": ["policy", "class", "base", "target", "readiness", "candidate_commit"],
      "properties": {
        "policy": {"const": "dset/scopes/ops/governance/release.md"},
        "class": {"enum": ["pending", "bootstrap", "small", "normal", "rc", "final", "breaking"]},
        "base": {"$ref": "#/$defs/release_base"},
        "target": {"oneOf": [{"const": "pending"}, {"$ref": "#/$defs/semver"}]},
        "readiness": {"const": "verification.md"},
        "candidate_commit": {"$ref": "#/$defs/sha_or_pending"}
      },
      "additionalProperties": false
    },
    "layered_release_reference": {
      "type": "object",
      "required": ["owner_change"],
      "properties": {"owner_change": {"$ref": "#/$defs/change_id"}},
      "additionalProperties": false
    },
    "release_base": {
      "type": "object",
      "required": ["ref", "commit", "version"],
      "properties": {
        "ref": {"type": "string", "minLength": 1},
        "commit": {"$ref": "#/$defs/sha_or_pending"},
        "version": {"oneOf": [{"const": "unversioned"}, {"const": "pending"}, {"$ref": "#/$defs/semver"}]}
      },
      "additionalProperties": false
    },
    "semver": {
      "type": "string",
      "pattern": "^(0|[1-9][0-9]*)\\.(0|[1-9][0-9]*)\\.(0|[1-9][0-9]*)(?:-rc\\.[1-9][0-9]*)?$"
    },
    "legacy_archive": {
      "type": "object",
      "required": ["date", "path"],
      "properties": {
        "date": {"type": "string", "format": "date"},
        "path": {"type": "string", "pattern": "^dset/changes/archive/[0-9]{4}-[0-9]{2}-[0-9]{2}-"}
      },
      "additionalProperties": false
    },
    "layered_archive": {
      "type": "object",
      "required": ["date", "path"],
      "properties": {
        "date": {"type": "string", "format": "date"},
        "path": {"type": "string", "pattern": "^dset/scopes/(?:meta|gov|tool|skill|ops)/changes/archive/[0-9]{4}-[0-9]{2}-[0-9]{2}-"}
      },
      "additionalProperties": false
    }
  },
  "allOf": [
    {
      "if": {"properties": {"schema_version": {"enum": [1.0, "1.0-draft"]}}},
      "then": {
        "required": ["adrs"],
        "not": {"required": ["decisions"]}
      },
      "else": {
        "required": ["release", "intake", "decisions", "contracts", "llm_session_ids"],
        "not": {"required": ["adrs"]},
        "properties": {
          "requirements": {"$ref": "#/$defs/requirement_ids"},
          "tests": {"$ref": "#/$defs/test_ids"},
          "evals": {"$ref": "#/$defs/eval_ids"},
          "intake": {"$ref": "#/$defs/intake_ids"},
          "decisions": {"$ref": "#/$defs/decision_ids"},
          "contracts": {"$ref": "#/$defs/contract_ids"},
          "stories": {"$ref": "#/$defs/story_ids"},
          "outcomes": {"$ref": "#/$defs/outcome_ids"}
        }
      }
    },
    {
      "if": {"properties": {"schema_version": {"const": "1.2"}}, "required": ["schema_version"]},
      "then": {
        "required": ["slug", "stories", "outcomes", "primary_layer", "affected_layers", "workspace", "dependencies", "target"],
        "properties": {
          "id": {"$ref": "#/$defs/change_id"},
          "release": {"$ref": "#/$defs/layered_release"},
          "archive": {"$ref": "#/$defs/layered_archive"}
        }
      },
      "else": {
        "not": {
          "anyOf": [
            {"required": ["slug"]},
            {"required": ["primary_layer"]},
            {"required": ["affected_layers"]},
            {"required": ["workspace"]},
            {"required": ["dependencies"]},
            {"required": ["target"]}
          ]
        },
        "properties": {
          "id": {"$ref": "#/$defs/kebab"},
          "release": {"$ref": "#/$defs/release"},
          "archive": {"$ref": "#/$defs/legacy_archive"}
        }
      }
    }
  ],
  "additionalProperties": false
}

files.dset/scopes/gov/schemas/governance.schem:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/dset/scopes/gov/schemas/governance.schema.json",
  "title": "DSET repository-governance registry",
  "type": "object",
  "required": ["schema_version", "profile", "rules", "workflows", "wrappers"],
  "properties": {
    "schema_version": {"const": 1.1},
    "profile": {
      "type": "object",
      "required": ["id", "version", "customization"],
      "properties": {
        "id": {"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"},
        "version": {"type": "string", "minLength": 1},
        "customization": {"enum": ["unmodified", "custom"]}
      },
      "additionalProperties": false
    },
    "rules": {
      "type": "array",
      "minItems": 1,
      "items": {"$ref": "#/$defs/rule"}
    },
    "workflows": {
      "type": "array",
      "minItems": 1,
      "items": {"$ref": "#/$defs/workflow"}
    },
    "wrappers": {
      "type": "array",
      "items": {"$ref": "#/$defs/wrapper"}
    }
  },
  "$defs": {
    "rule": {
      "type": "object",
      "required": ["id", "layer", "path", "owner", "applicability", "reason", "depends_on", "precedence_over", "customization", "source"],
      "properties": {
        "id": {"type": "string", "pattern": "^[A-Z0-9]+(?:-[A-Z0-9]+)+$"},
        "layer": {"enum": ["META", "GOV", "TOOL", "SKILL", "OPS"]},
        "path": {"type": "string", "minLength": 1},
        "owner": {"type": "string", "minLength": 1},
        "applicability": {"enum": ["applicable", "not-applicable"]},
        "reason": {"type": "string", "minLength": 1},
        "depends_on": {"type": "array", "uniqueItems": true, "items": {"type": "string"}},
        "precedence_over": {"type": "array", "uniqueItems": true, "items": {"type": "string"}},
        "customization": {"enum": ["unmodified", "custom"]},
        "source": {
          "type": "object",
          "required": ["profile", "version", "template", "sha256"],
          "properties": {
            "profile": {"type": "string", "minLength": 1},
            "version": {"type": "string", "minLength": 1},
            "template": {"type": "string", "minLength": 1},
            "sha256": {"type": "string", "pattern": "^[0-9a-f]{64}$"}
          },
          "additionalProperties": false
        }
      },
      "additionalProperties": false
    },
    "workflow": {
      "type": "object",
      "required": ["id", "rules"],
      "properties": {
        "id": {"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"},
        "rules": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"type": "string"}}
      },
      "additionalProperties": false
    },
    "wrapper": {
      "type": "object",
      "required": ["workflow", "path", "sha256"],
      "properties": {
        "workflow": {"type": "string", "minLength": 1},
        "path": {"type": "string", "minLength": 1},
        "sha256": {"type": "string", "pattern": "^[0-9a-f]{64}$"}
      },
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}

files.dset/scopes/gov/schemas/intake.schema.js:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/dset/scopes/gov/schemas/intake.schema.json",
  "title": "DSET project intake registry",
  "oneOf": [
    {
      "type": "object",
      "required": ["schema_version", "scope_mode", "scopes", "items"],
      "properties": {
        "schema_version": {"const": 1.0},
        "scope_mode": {"const": "multi-scope"},
        "scopes": {"type": "array", "minItems": 5, "maxItems": 5, "uniqueItems": true, "items": {"$ref": "#/$defs/scope"}},
        "items": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/legacy_item"}}
      },
      "additionalProperties": false
    },
    {
      "type": "object",
      "required": ["schema_version", "items"],
      "properties": {
        "schema_version": {"const": "1.1"},
        "items": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/layered_item"}}
      },
      "additionalProperties": false
    }
  ],
  "$defs": {
    "scope": {
      "type": "object",
      "required": ["id", "id_segment", "kind", "name"],
      "properties": {
        "id": {"enum": ["meta", "gov", "tool", "skill", "ops"]},
        "id_segment": {"enum": ["META", "GOV", "TOOL", "SKILL", "OPS"]},
        "kind": {"const": "layer"},
        "name": {"type": "string", "minLength": 1},
        "path": {"type": ["string", "null"]}
      },
      "additionalProperties": false
    },
    "legacy_item": {
      "type": "object",
      "required": ["id", "scope", "type", "status", "title", "statement", "owner_change", "decision", "llm_session_ids"],
      "properties": {
        "id": {"$ref": "#/$defs/intake_id"},
        "scope": {"$ref": "#/$defs/layer"},
        "type": {"enum": ["problem", "opportunity", "question"]},
        "status": {"enum": ["open", "accepted", "resolved", "closed"]},
        "title": {"type": "string", "minLength": 1},
        "statement": {"type": "string", "minLength": 1},
        "owner_change": {"oneOf": [{"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"}, {"const": "pending"}, {"type": "null"}]},
        "decision": {"$ref": "#/$defs/decision"},
        "llm_session_ids": {"$ref": "#/$defs/llm_session_ids"},
        "rationale": {"$ref": "#/$defs/rationale"},
        "external_refs": {"$ref": "#/$defs/external_refs"}
      },
      "additionalProperties": false
    },
    "layered_item": {
      "type": "object",
      "required": ["id", "scope", "type", "status", "title", "statement", "owner_change", "decision", "llm_session_ids"],
      "properties": {
        "id": {"$ref": "#/$defs/intake_id"},
        "scope": {"$ref": "#/$defs/layer"},
        "type": {"enum": ["problem", "opportunity", "question"]},
        "status": {"enum": ["open", "accepted", "resolved", "closed"]},
        "title": {"type": "string", "minLength": 1},
        "statement": {"type": "string", "minLength": 1},
        "owner_change": {"oneOf": [{"type": "string", "pattern": "^[A-Z][A-Z0-9]*-CHANGE-(?:META|GOV|TOOL|SKILL|OPS)-[0-9]{3,}$"}, {"const": "pending"}, {"type": "null"}]},
        "decision": {"$ref": "#/$defs/decision"},
        "llm_session_ids": {"$ref": "#/$defs/llm_session_ids"},
        "rationale": {"$ref": "#/$defs/rationale"},
        "external_refs": {"$ref": "#/$defs/external_refs"}
      },
      "additionalProperties": false
    },
    "layer": {"enum": ["meta", "gov", "tool", "skill", "ops"]},
    "intake_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-(?:PROBLEM|OPPORTUNITY|QUESTION)(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"},
    "decision": {"oneOf": [{"type": "string", "pattern": "^[A-Z][A-Z0-9]*-DECISION(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}, {"const": "pending"}, {"type": "null"}]},
    "llm_session_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$"}},
    "rationale": {"type": "string", "minLength": 1, "maxLength": 2048},
    "external_refs": {"type": "array", "uniqueItems": true, "items": {"type": "string", "minLength": 1}}
  }
}

