    "persistence": {"enum": ["persisted", "unavailable"]},
    "public_entrypoint": {"enum": ["dset", "dset-clarify", "dset-diagnose", "dset-prototype", "dset-release"]},
    "root_run_id": {"$ref": "#/$defs/id"},
    "latest_run_id": {"$ref": "#/$defs/id"},
    "scope": {"$ref": "#/$defs/scope"},
    "objective": {"type": "string", "minLength": 1, "maxLength": 1024},
    "ruleset_identity": {"oneOf": [{"$ref": "#/$defs/id"}, {"type": "null"}]},
    "completed": {
      "type": "array",
      "maxItems": 64,
      "items": {"$ref": "#/$defs/work_pointer"}
    },
    "pending": {
      "type": "array",
      "maxItems": 32,
      "items": {"$ref": "#/$defs/work_pointer"}
    },
    "authorization": {
      "type": "object",
      "required": ["class", "state"],
      "properties": {
        "class": {"enum": ["read-only", "repository-write", "external-write", "publication", "unknown"]},
        "state": {"enum": ["granted", "not-granted", "consumed", "unknown"]}
      },
      "additionalProperties": false
    },
    "touched_paths": {
      "type": "array",
      "maxItems": 64,
      "uniqueItems": true,
      "items": {"$ref": "#/$defs/relative_path"}
    },
    "authority_snapshot": {
      "type": "object",
      "required": ["git_commit", "working_tree_digest", "change_manifest", "proof_ids", "hosted_refs"],
      "properties": {
        "git_commit": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{40}$"}, {"type": "null"}]},
        "working_tree_digest": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{64}$"}, {"type": "null"}]},
        "change_manifest": {"oneOf": [{"$ref": "#/$defs/relative_path"}, {"type": "null"}]},
        "proof_ids": {"type": "array", "maxItems": 32, "uniqueItems": true, "items": {"$ref": "#/$defs/id"}},
        "hosted_refs": {"type": "array", "maxItems": 16, "uniqueItems": true, "items": {"$ref": "#/$defs/id"}}
      },
      "additionalProperties": false
    },
    "next": {
      "type": "object",
      "required": ["mode", "reason_code", "requires_authorization"],
      "properties": {
        "mode": {"enum": ["initialize", "repair-governance", "decompose", "diagnose", "clarify", "landscape", "prototype", "decide", "plan-proof", "plan-implementation", "implement", "verify", "triage-work", "release", "complete"]},
        "reason_code": {"$ref": "#/$defs/id"},
        "requires_authorization": {"enum": ["none", "repository-write", "external-write", "publication"]}
      },
      "additionalProperties": false
    }
  },
  "$defs": {
    "id": {"type": "string", "pattern": "^[A-Za-z0-9][A-Za-z0-9._:-]{0,127}$"},
    "llm_session_id": {"type": "string", "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$", "maxLength": 160},
    "rationale": {"type": "string", "minLength": 1, "maxLength": 1024},
    "nullable_scope": {"oneOf": [{"type": "string", "pattern": "^[A-Za-z0-9][A-Za-z0-9._:/-]{0,127}$"}, {"type": "null"}]},
    "relative_path": {"type": "string", "maxLength": 512, "pattern": "^(?!/)(?!.*\\.\\./)[A-Za-z0-9._-]+(?:/[A-Za-z0-9._-]+)*$"},
    "scope": {
      "type": "object",
      "required": ["repository", "workspace", "project", "package", "change", "target"],
      "properties": {
        "repository": {"$ref": "#/$defs/nullable_scope"},
        "workspace": {"$ref": "#/$defs/nullable_scope"},
        "project": {"$ref": "#/$defs/nullable_scope"},
        "package": {"$ref": "#/$defs/nullable_scope"},
        "change": {"$ref": "#/$defs/nullable_scope"},
        "target": {"$ref": "#/$defs/target"}
      },
      "additionalProperties": false
    },
    "target": {
      "type": "object",
      "required": ["repository", "work_areas"],
      "properties": {
        "repository": {"type": "boolean"},
        "work_areas": {"type": "array", "maxItems": 32, "uniqueItems": true, "items": {"$ref": "#/$defs/id"}}
      },
      "oneOf": [
        {"properties": {"repository": {"const": true}, "work_areas": {"maxItems": 0}}},
        {"properties": {"repository": {"const": false}, "work_areas": {"minItems": 1}}}
      ],
      "additionalProperties": false
    },
    "work_pointer": {
      "type": "object",
      "required": ["kind", "id", "path"],
      "properties": {
        "kind": {"enum": ["artifact", "workflow", "proof", "diagnostic", "handoff"]},
        "id": {"oneOf": [{"$ref": "#/$defs/id"}, {"type": "null"}]},
        "path": {"oneOf": [{"$ref": "#/$defs/relative_path"}, {"type": "null"}]}
      },
      "anyOf": [
        {"properties": {"id": {"$ref": "#/$defs/id"}}},
        {"properties": {"path": {"$ref": "#/$defs/relative_path"}}}
      ],
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}

files.dset/scopes/skill/schemas/skill-run.sche:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/dset/scopes/skill/schemas/skill-run.schema.json",
  "title": "DSET local skill-run record",
  "type": "object",
  "required": ["schema_version", "session_id", "llm_session_ids", "run_id", "root_run_id", "parent_run_id", "invocation_source", "checkpoint", "started_at", "finished_at", "status", "persistence", "scope", "skill_id", "workflow_id", "mode_id", "ruleset_identity", "parameters", "outputs", "diagnostics", "next_signals", "budget"],
  "properties": {
    "schema_version": {"const": "1.2"},
    "session_id": {"$ref": "#/$defs/id"},
    "llm_session_ids": {"type": "array", "maxItems": 8, "uniqueItems": true, "items": {"$ref": "#/$defs/llm_session_id"}},
    "rationale": {"$ref": "#/$defs/rationale"},
    "run_id": {"$ref": "#/$defs/id"},
    "root_run_id": {"$ref": "#/$defs/id"},
    "parent_run_id": {"oneOf": [{"$ref": "#/$defs/id"}, {"type": "null"}]},
    "invocation_source": {"enum": ["operator", "public-skill", "chained-skill", "governed-model", "delegated-run"]},
    "checkpoint": {"oneOf": [{"$ref": "#/$defs/relative_path"}, {"type": "null"}]},
    "started_at": {"type": "string", "format": "date-time", "maxLength": 40},
    "finished_at": {"oneOf": [{"type": "string", "format": "date-time", "maxLength": 40}, {"type": "null"}]},
    "status": {"enum": ["running", "succeeded", "failed", "stopped", "interrupted"]},
    "persistence": {"enum": ["persisted", "unavailable"]},
    "scope": {
      "type": "object",
      "required": ["repository", "project", "package", "change", "target"],
      "properties": {
        "repository": {"$ref": "#/$defs/nullable_scope"},
        "project": {"$ref": "#/$defs/nullable_scope"},
        "package": {"$ref": "#/$defs/nullable_scope"},
        "change": {"$ref": "#/$defs/nullable_scope"},
        "target": {"$ref": "#/$defs/target"}
      },
      "additionalProperties": false
    },
    "skill_id": {"$ref": "#/$defs/nullable_id"},
    "workflow_id": {"$ref": "#/$defs/nullable_id"},
    "mode_id": {"$ref": "#/$defs/nullable_id"},
    "ruleset_identity": {"$ref": "#/$defs/nullable_id"},
    "parameters": {
      "type": "array",
      "maxItems": 32,
      "items": {"$ref": "#/$defs/parameter"}
    },
    "outputs": {"type": "array", "maxItems": 32, "items": {"$ref": "#/$defs/relative_path"}},
    "diagnostics": {"type": "array", "maxItems": 32, "items": {"$ref": "#/$defs/stable_code"}},
    "next_signals": {
      "type": "array",
      "maxItems": 16,
      "items": {"enum": ["initialize", "repair-governance", "decompose", "diagnose", "clarify", "landscape", "prototype", "decide", "plan-proof", "plan-implementation", "implement", "verify", "triage-work", "release", "complete"]}
    },
    "budget": {
      "type": "object",
      "required": ["profile", "requested_model", "requested_effort", "effective_model", "effective_effort", "attestation", "planned_subagents", "actual_subagents", "planned_rounds", "actual_rounds", "deviations"],
      "properties": {
        "profile": {"enum": ["low", "medium", "high"]},
        "requested_model": {"$ref": "#/$defs/nullable_id"},
        "requested_effort": {"$ref": "#/$defs/nullable_id"},
        "effective_model": {"$ref": "#/$defs/nullable_id"},
        "effective_effort": {"$ref": "#/$defs/nullable_id"},
        "attestation": {"enum": ["confirmed", "runtime-default-unverified", "unsupported"]},
        "planned_subagents": {"type": "integer", "minimum": 0, "maximum": 6},
        "actual_subagents": {"type": "integer", "minimum": 0, "maximum": 6},
        "planned_rounds": {"type": "integer", "minimum": 0, "maximum": 3},
        "actual_rounds": {"type": "integer", "minimum": 0, "maximum": 3},
        "deviations": {"type": "array", "maxItems": 8, "items": {"$ref": "#/$defs/stable_code"}}
      },
      "allOf": [
        {
          "if": {"properties": {"profile": {"const": "low"}}},
          "then": {"properties": {"planned_subagents": {"maximum": 1}, "actual_subagents": {"maximum": 1}, "planned_rounds": {"maximum": 1}, "actual_rounds": {"maximum": 1}}}
        },
        {
          "if": {"properties": {"profile": {"const": "medium"}}},
          "then": {"properties": {"planned_subagents": {"maximum": 3}, "actual_subagents": {"maximum": 3}, "planned_rounds": {"maximum": 2}, "actual_rounds": {"maximum": 2}}}
        }
      ],
      "additionalProperties": false
    },
    "usage": {
      "oneOf": [
        {"type": "null"},
        {
          "type": "object",
          "properties": {
            "input_tokens": {"type": "integer", "minimum": 0},
            "output_tokens": {"type": "integer", "minimum": 0},
            "currency": {"type": "string", "pattern": "^[A-Z]{3}$"},
            "cost": {"type": "number", "minimum": 0}
          },
          "additionalProperties": false
        }
      ]
    }
  },
  "allOf": [
    {
      "if": {"properties": {"status": {"const": "running"}}},
      "then": {"properties": {"finished_at": {"type": "null"}, "persistence": {"const": "persisted"}}},
      "else": {"properties": {"finished_at": {"type": "string", "format": "date-time", "maxLength": 40}}}
    },
    {
      "if": {"properties": {"persistence": {"const": "unavailable"}}},
      "then": {"properties": {"status": {"enum": ["succeeded", "failed", "stopped", "interrupted"]}}}
    }
  ],
  "$defs": {
    "id": {"type": "string", "pattern": "^[A-Za-z0-9][A-Za-z0-9._:-]{0,127}$"},
    "llm_session_id": {"type": "string", "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$", "maxLength": 160},
    "rationale": {"type": "string", "minLength": 1, "maxLength": 1024},
    "nullable_id": {"oneOf": [{"$ref": "#/$defs/id"}, {"type": "null"}]},
    "nullable_scope": {"oneOf": [{"type": "string", "pattern": "^[A-Za-z0-9][A-Za-z0-9._:/-]{0,127}$"}, {"type": "null"}]},
    "target": {
      "type": "object",
      "required": ["repository", "work_areas"],
      "properties": {
        "repository": {"type": "boolean"},
        "work_areas": {"type": "array", "maxItems": 32, "uniqueItems": true, "items": {"$ref": "#/$defs/id"}}
      },
      "oneOf": [
        {"properties": {"repository": {"const": true}, "work_areas": {"maxItems": 0}}},
        {"properties": {"repository": {"const": false}, "work_areas": {"minItems": 1}}}
      ],
      "additionalProperties": false
    },
    "relative_path": {"type": "string", "maxLength": 512, "pattern": "^(?!/)(?!.*\\.\\./)[A-Za-z0-9._-]+(?:/[A-Za-z0-9._-]+)*$"},
    "stable_code": {"type": "string", "maxLength": 64, "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+){1,5}$"},
    "parameter_name": {"enum": ["operation", "change_profile", "budget_profile", "applicability", "authorization", "scope_kind", "source_kind", "target_kind", "result_class", "risk_class"]},
    "parameter": {
      "oneOf": [
        {
          "type": "object",
          "required": ["name", "representation", "value"],
          "properties": {
            "name": {"$ref": "#/$defs/parameter_name"},
            "representation": {"const": "category"},
            "value": {"enum": ["none", "small", "standard", "large", "defect", "adoption", "low", "medium", "high", "applicable", "not-applicable", "read-only", "write-authorized", "automatic", "manual", "local", "hosted", "success", "failure", "stopped", "unknown"]}
          },
          "additionalProperties": false
        },
        {
          "type": "object",
          "required": ["name", "representation", "value"],
          "properties": {
            "name": {"$ref": "#/$defs/parameter_name"},
            "representation": {"const": "sha256"},
            "value": {"type": "string", "pattern": "^[0-9a-f]{64}$"}
          },
          "additionalProperties": false
        },
        {
          "type": "object",
          "required": ["name", "representation", "value"],
          "properties": {
            "name": {"$ref": "#/$defs/parameter_name"},
            "representation": {"const": "redacted"},
            "value": {"const": "[redacted]"}
          },
          "additionalProperties": false
        }
      ]
    }
  },
  "additionalProperties": false
}

files.dset/scopes/tool/schemas/traceability.sc:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/dset/scopes/tool/schemas/traceability.schema.json",
  "title": "DSET traceability index",
  "type": "object",
  "required": ["schema_version", "repository", "changes", "lineage"],
  "properties": {
    "schema_version": {"enum": [1.1, "1.2"]},
    "repository": {"type": "string"},
    "changes": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["id", "status", "path", "packages", "requirements", "tests", "evals", "intake", "decisions", "contracts", "stories", "outcomes", "pull_request", "evidence"],
        "properties": {
          "id": {"type": "string"},
          "slug": {"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"},
          "status": {"type": "string"},
          "path": {"type": "string"},
          "primary_layer": {"enum": ["meta", "gov", "tool", "skill", "ops"]},
          "affected_layers": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"enum": ["meta", "gov", "tool", "skill", "ops"]}},
          "workspace": {"$ref": "#/$defs/workspace"},
          "dependencies": {"type": "array", "items": {"$ref": "#/$defs/dependency"}},
          "target": {"$ref": "#/$defs/target"},
          "packages": {"type": "array", "items": {"type": "string"}},
          "requirements": {"type": "array", "items": {"type": "string"}},
          "tests": {"type": "array", "items": {"type": "string"}},
          "evals": {"type": "array", "items": {"type": "string"}},
          "intake": {"type": "array", "items": {"type": "string"}},
          "decisions": {"type": "array", "items": {"type": "string"}},
          "contracts": {"type": "array", "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-CONTRACT(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
          "stories": {"type": "array", "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-STORY(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
          "outcomes": {"type": "array", "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-OUTCOME(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
          "pull_request": {"type": "string", "format": "uri"},
          "evidence": {"type": "array", "items": {"type": "string"}}
        },
        "additionalProperties": false
      }
    },
    "lineage": {
      "type": "array",
      "items": {"$ref": "#/$defs/lineage_node"}
    }
  },
  "allOf": [
    {
      "if": {"properties": {"schema_version": {"const": "1.2"}}, "required": ["schema_version"]},
      "then": {
        "properties": {
          "changes": {
            "items": {
              "required": ["slug", "primary_layer", "affected_layers", "workspace", "dependencies", "target"],
              "properties": {"id": {"$ref": "#/$defs/change_id"}}
            }
          }
        }
      },
      "else": {
        "properties": {
          "changes": {
            "items": {"not": {"anyOf": [{"required": ["slug"]}, {"required": ["primary_layer"]}, {"required": ["affected_layers"]}, {"required": ["workspace"]}, {"required": ["dependencies"]}, {"required": ["target"]}]}}
          }
        }
      }
    }
  ],
  "$defs": {
    "lineage_id": {"type": "string", "pattern": "^[A-Z0-9]+(?:-[A-Z0-9]+)+$"},
    "lineage_node": {
      "type": "object",
      "required": ["id", "artifact_id", "path", "child_of", "parent_to"],
      "properties": {
        "id": {"$ref": "#/$defs/lineage_id"},
        "artifact_id": {"$ref": "#/$defs/lineage_id"},
        "path": {"type": "string", "minLength": 1},
        "child_of": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/lineage_id"}},
        "parent_to": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/lineage_id"}}
      },
      "additionalProperties": false
    },
    "change_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-CHANGE-(?:META|GOV|TOOL|SKILL|OPS)-[0-9]{3,}$"},
    "trace_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-(?:REQUIREMENT|SCENARIO|INVARIANT|TEST|EVAL|TASK|PROBLEM|OPPORTUNITY|QUESTION|DECISION|CONTRACT|STORY|OUTCOME|CHANGE)(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"},
    "sha_or_pending": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{40}$"}, {"const": "pending"}]},
    "pull_request": {
      "type": "object",
      "required": ["repository", "number", "url"],
      "properties": {
        "repository": {"type": "string", "pattern": "^[^/]+/[^/]+$"},
        "number": {"oneOf": [{"type": "integer", "minimum": 1}, {"const": "pending"}]},
        "url": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "workspace": {
      "type": "object",
      "required": ["isolation", "branch", "base_ref", "base_commit", "head_commit"],
      "properties": {
        "isolation": {"enum": ["integration-branch", "branch-worktree"]},
        "branch": {"type": "string", "minLength": 1},
        "base_ref": {"type": "string", "minLength": 1},
        "base_commit": {"$ref": "#/$defs/sha_or_pending"},
        "head_commit": {"$ref": "#/$defs/sha_or_pending"}
      },
      "additionalProperties": false
    },
    "target": {
      "type": "object",
      "required": ["repository", "work_areas"],
      "properties": {
        "repository": {"type": "boolean"},
        "work_areas": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"}}
      },
      "oneOf": [
        {
          "properties": {
            "repository": {"const": true},
            "work_areas": {"maxItems": 0}
          }
        },
        {
          "properties": {
            "repository": {"const": false},
            "work_areas": {"minItems": 1}
          }
        }
      ],
      "additionalProperties": false
    },
    "dependency": {
      "type": "object",
      "required": ["change_id", "pull_request", "required_commit", "consumes", "claim", "use", "evidence", "checked_at", "reopen_when", "status"],
      "properties": {
        "change_id": {"$ref": "#/$defs/change_id"},
        "pull_request": {"$ref": "#/$defs/pull_request"},
        "required_commit": {"$ref": "#/$defs/sha_or_pending"},
        "consumes": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/trace_id"}},
        "claim": {"type": "string", "minLength": 1},
        "use": {"type": "string", "minLength": 1},
        "evidence": {"type": "string", "minLength": 1},
        "checked_at": {"type": "string", "format": "date"},
        "reopen_when": {"type": "string", "minLength": 1},
        "status": {"enum": ["planned", "available", "integrated", "blocked", "stale"]}
      },
      "allOf": [
        {
          "if": {"properties": {"status": {"enum": ["available", "integrated"]}}, "required": ["status"]},
          "then": {
            "properties": {
              "pull_request": {
                "properties": {
                  "number": {"type": "integer", "minimum": 1},
                  "url": {"type": "string", "format": "uri", "pattern": "^https://"}
                }
              },
              "required_commit": {"type": "string", "pattern": "^[0-9a-f]{40}$"}
            }
          }
        }
      ],
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}
